const rawUrl = $input.first().json.linkedin_url || '';

function normalizeLinkedInUrl(url) {
  if (!url || typeof url !== 'string') return null;

  let normalized = url.toLowerCase().trim();

  // Remove protocol
  normalized = normalized.replace(/^https?:\/\//, '');

  // Remove www. and country subdomains (uk., de., fr., etc.)
  normalized = normalized.replace(/^(www\.|[a-z]{2}\.)?linkedin\.com/, 'linkedin.com');

  // Remove trailing slash
  normalized = normalized.replace(/\/$/, '');

  // Remove query params and hash
  normalized = normalized.split('?')[0].split('#')[0];

  // Validate it looks like a LinkedIn URL
  if (!normalized.startsWith('linkedin.com/in/')) {
    // Try to extract just the profile path
    const match = normalized.match(/linkedin\.com\/in\/([\w-]+)/);
    if (match) {
      normalized = 'linkedin.com/in/' + match[1];
    } else {
      return null;
    }
  }

  return normalized;
}

// Map HeyReach event types to our activity types
// HeyReach events: Lead Tag Updated, Campaign Completed, Viewed Profile, Liked Post,
// Follow Sent, Inmail Sent, Reply Received, Message Sent, Connection Request Accept
const eventTypeMap = {
  // Connection events
  'connection_request_sent': 'connection_sent',
  'connection_request_accept': 'connection_accepted',
  'connection_request_accepted': 'connection_accepted',
  // Message events  
  'message_sent': 'message_sent',
  'inmail_sent': 'message_sent',
  'reply_received': 'message_replied',
  'first_inmail_reply_received': 'message_replied',
  'message_reply_received': 'message_replied',
  // Engagement events
  'viewed_profile': 'profile_viewed',
  'follow_sent': 'follow_sent',
  'liked_post': 'liked_post',
  // Campaign events
  'campaign_completed': 'campaign_completed',
  'lead_tag_updated': 'tag_updated'
};

const inputData = $input.first().json;
const normalizedUrl = normalizeLinkedInUrl(rawUrl);
const mappedActivityType = eventTypeMap[inputData.event_type] || inputData.event_type;

return [{
  json: {
    ...inputData,
    normalized_linkedin_url: normalizedUrl,
    original_linkedin_url: rawUrl,
    mapped_activity_type: mappedActivityType,
    is_reply_event: ['message_replied', 'message_reply_received', 'reply_received', 'first_inmail_reply_received'].includes(inputData.event_type)
  }
}];

// Merge contact data from lookup or creation
const normalizedData = $('Normalize LinkedIn URL').first().json;
const contactResult = $input.first().json;

// Contact data comes as array from Postgres node or as object
let contact;
if (Array.isArray(contactResult)) {
  contact = contactResult[0];
} else if (contactResult && contactResult.id) {
  contact = contactResult;
} else {
  contact = null;
}

// Check if this is a new contact by seeing if we came from Create New Contact path
const isNewContact = contact && contact.id ? true : false;

return [{
  json: {
    ...normalizedData,
    contact_id: contact?.id || null,
    contact_email: contact?.email || normalizedData.email,
    contact_first_name: contact?.first_name || normalizedData.first_name,
    contact_last_name: contact?.last_name || normalizedData.last_name,
    is_new_contact: isNewContact
  }
}];

const prevData = $('Merge Contact Data').first().json;
const campaignContext = $input.first().json;

// Handle array response from Postgres
const ctx = Array.isArray(campaignContext) ? campaignContext[0] : campaignContext;

return [{
  json: {
    ...prevData,
    campaign_contact_id: ctx?.campaign_contact_id || null,
    campaign_contact_channel_id: ctx?.campaign_contact_channel_id || null,
    campaign_channel_id: ctx?.campaign_channel_id || 'cc111111-2222-3333-4444-555566667777'
  }
}];

