const contextData = $('Merge Campaign Context').first().json;
const geminiResponse = $input.first().json;

// Extract classification from Gemini response
let classification = 'neutral';
try {
  const text = geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text || '';
  classification = text.trim().toLowerCase().replace(/[^a-z_]/g, '');

  // Validate it's one of our expected values
  const validClassifications = ['positive_reply', 'interested_secondary', 'not_now_polite', 'not_interested', 'unsubscribe', 'neutral'];
  if (!validClassifications.includes(classification)) {
    classification = 'neutral';
  }
} catch (e) {
  classification = 'neutral';
}

// Map classification to branch
const branchMap = {
  'positive_reply': 'A',
  'interested_secondary': 'A+',
  'not_now_polite': 'B',
  'not_interested': null,
  'unsubscribe': null,
  'neutral': null
};

const triggerEvent = classification;
const suggestedBranch = branchMap[classification];
const isOptOut = ['not_interested', 'unsubscribe'].includes(classification);

return [{
  json: {
    ...contextData,
    classification: classification,
    trigger_event: triggerEvent,
    suggested_branch: suggestedBranch,
    is_opt_out: isOptOut,
    gemini_raw_response: geminiResponse
  }
}];

const prevData = $('Process Classification').first().json;
const branchResult = $input.first().json;

// Get branch from function result
const assignedBranch = Array.isArray(branchResult) 
  ? branchResult[0]?.assigned_branch 
  : branchResult?.assigned_branch;

return [{
  json: {
    ...prevData,
    assigned_branch: assignedBranch || prevData.suggested_branch
  }
}];
